        }
        /**
         * Get relative path
         * 
         * @param string $path
         * @param string $base
         * @return string
         */
        private function getRelativePath(string $path, string $base): string
        {
            return str_replace($base . DIRECTORY_SEPARATOR, '', $path);
        }
    }
}

