namespace PhpFileMerger\Model {
    /**
     * Configuration for the merge operation
     */
    readonly class Config
    {
        /**
         * @param string $projectRoot Absolute path to the project root directory
         * @param string $entryPoint Absolute path to the entry point PHP file
         * @param string $outputPath Absolute path where the merged file should be written
         * @param bool $excludeEntryPoint Whether to exclude the entry point code from output (for .include.php)
         * @param int $indentSpaces Number of spaces for indentation (default: 4)
         * @param string|null $vendorDir Path to vendor directory (null for auto-detect)
         * @param array<string> $excludePaths List of file paths to exclude from merging
         * @param bool $removeStrictTypes Whether to remove declare(strict_types=1)
         * @param bool $removeAutoloadRequires Whether to remove vendor/autoload.php requires
         * @param string|null $headerTemplate Custom header template (null for default)
         */
        public function __construct(public string $projectRoot, public string $entryPoint, public string $outputPath, public bool $excludeEntryPoint = false, public int $indentSpaces = 4, public ?string $vendorDir = null, public array $excludePaths = [], public bool $removeStrictTypes = true, public bool $removeAutoloadRequires = true, public ?string $headerTemplate = null)
        {
        }
        /**
         * Get the vendor directory path
         */
        public function getVendorDir(): string
        {
            if ($this->vendorDir !== null) {
                return $this->vendorDir;
            }
            return $this->projectRoot . '/vendor';
        }
        /**
         * Get the composer.json path
         */
        public function getComposerJsonPath(): string
        {
            return $this->projectRoot . '/composer.json';
        }
        /**
         * Get indentation string
         */
        public function getIndent(): string
        {
            return str_repeat(' ', $this->indentSpaces);
        }
    }
}

// file: src/Model/PHPFile.php
namespace PhpFileMerger\Model {
    /**
     * Represents a parsed PHP file with its dependencies and declarations
     */
    readonly class PHPFile
    {
        /**
         * @param string $path Absolute path to the PHP file
         * @param string|null $namespace The namespace declared in this file (null for global namespace)
         * @param array<string> $declaredClasses List of fully-qualified class names declared in this file
         * @param array<string> $declaredInterfaces List of fully-qualified interface names declared in this file
         * @param array<string> $declaredTraits List of fully-qualified trait names declared in this file
         * @param array<string> $declaredEnums List of fully-qualified enum names declared in this file (PHP 8.1+)
         * @param array<ClassReference> $references List of class references used in this file
         * @param array<string, string> $useStatements Map of alias => fully-qualified class name from use statements
         */
        public function __construct(public string $path, public ?string $namespace, public array $declaredClasses, public array $declaredInterfaces, public array $declaredTraits, public array $declaredEnums, public array $references, public array $useStatements)
        {
        }
        /**
         * Get all declared types (classes, interfaces, traits, enums)
         * @return array<string>
         */
        public function getAllDeclaredTypes(): array
        {
            return array_merge($this->declaredClasses, $this->declaredInterfaces, $this->declaredTraits, $this->declaredEnums);
        }
        /**
         * Get all unique referenced class names
         * @return array<string>
         */
        public function getReferencedClassNames(): array
        {
            $names = array_map(fn(ClassReference $ref) => $ref->fullyQualifiedName, $this->references);
            return array_unique($names);
        }
        /**
         * Get class names that are "hard" dependencies (must be defined before this file).
         * Only extends, implements, and trait use require ordering.
         * @return array<string>
         */
        public function getHardDependencyClassNames(): array
        {
            $names = [];
            foreach ($this->references as $ref) {
                if (in_array($ref->type, ['extends', 'implements', 'use'], true)) {
                    $names[] = $ref->fullyQualifiedName;
                }
            }
            return array_unique($names);
        }
    }
}

