                // Track parent class
                if ($node->extends !== null) {
                    $this->addReference($node->extends, 'extends', $node->getLine());
                }
                // Track implemented interfaces
                foreach ($node->implements as $interface) {
                    $this->addReference($interface, 'implements', $node->getLine());
                }
