         */
        protected function updateMessage(): void
        {
            $this->message = $this->rawMessage;
            if (-1 === $this->getStartLine()) {
                $this->message .= ' on unknown line';
            } else {
                $this->message .= ' on line ' . $this->getStartLine();
            }
        }
