                    $i += 3;
                    $c += 3;
                }
            }
            return $tokens;
        }
        /** @param Token[] $tokens */
        protected function isKeywordContext(array $tokens, int $pos): bool
        {
            $prevToken = $this->getPreviousNonSpaceToken($tokens, $pos);
            if ($prevToken === null) {
                return false;
            }
            return $prevToken->id !== \T_OBJECT_OPERATOR && $prevToken->id !== \T_NULLSAFE_OBJECT_OPERATOR;
        }
