                    array_splice($tokens, $i, 1, $replacement);
                    $c += \count($replacement) - 1;
                    continue;
                }
            }
            return $tokens;
        }
        public function reverseEmulate(string $code, array $tokens): array
        {
            // ?-> was not valid code previously, don't bother.
            return $tokens;
        }
    }
}

