                if (!isset($this->dropTokens[$token->id])) {
                    break;
                }
                if ($token->id === \T_COMMENT || $token->id === \T_DOC_COMMENT) {
                    return $this->createCommentFromToken($token, $tokenPos);
                }
            }
            return null;
        }
