            if ($numStmts !== 0 && $node->stmts[$numStmts - 1] instanceof Nop) {
                $nopAttrs = $node->stmts[$numStmts - 1]->getAttributes();
                if (isset($nopAttrs['endLine'])) {
                    $node->setAttribute('endLine', $nopAttrs['endLine']);
