            AssignOp\ShiftRight::class => [160, -1, -1],
            AssignOp\Pow::class => [160, -1, -1],
            AssignOp\Coalesce::class => [160, -1, -1],
            Expr\YieldFrom::class => [170, -1, -1],
            Expr\Yield_::class => [175, -1, -1],
            Expr\Print_::class => [180, -1, -1],
