            $this->triggerDeprecations = true;
            if (null !== (new \ReflectionFunction($code))->getClosureThis()) {
                return $code;
            }
            set_error_handler(static function () {
            });
            try {
                if ($c = \Closure::bind($code, $this->command)) {
                    $code = $c;
                }
