        private function resolveStyle(TableStyle|string $name): TableStyle
        {
            if ($name instanceof TableStyle) {
                return $name;
            }
            return self::$styles[$name] ?? throw new InvalidArgumentException(\sprintf('Style "%s" is not defined.', $name));
