         * Sets a normalizer for the response.
         *
         * @param callable(mixed):mixed $normalizer
         *
         * @return $this
         */
        public function setNormalizer(callable $normalizer): static
        {
            $this->normalizer = $normalizer(...);
            return $this;
        }
        /**
         * Gets the normalizer for the response.
         *
         * @return (callable(mixed):mixed)|null
         */
        public function getNormalizer(): ?callable
        {
            return $this->normalizer;
        }
        protected function isAssoc(array $array): bool
        {
            return (bool) \count(array_filter(array_keys($array), 'is_string'));
        }
        public function isTrimmable(): bool
        {
            return $this->trimmable;
        }
        /**
         * @return $this
         */
        public function setTrimmable(bool $trimmable): static
        {
            $this->trimmable = $trimmable;
            return $this;
        }
    }
}

// file: vendor/symfony/console/Question/ChoiceQuestion.php
namespace Symfony\Component\Console\Question {
    use Symfony\Component\Console\Exception\InvalidArgumentException;
    /**
     * Represents a choice question.
     *
     * @author Fabien Potencier <fabien@symfony.com>
     */
    class ChoiceQuestion extends Question
    {
        private bool $multiselect = false;
        private string $prompt = ' > ';
        private string $errorMessage = 'Value "%s" is invalid';
        /**
         * @param string                                   $question The question to ask to the user
         * @param array<string|bool|int|float|\Stringable> $choices  The list of available choices
         * @param string|bool|int|float|null               $default  The default answer to return
         */
        public function __construct(string $question, private array $choices, string|bool|int|float|null $default = null)
        {
            if (!$choices) {
                throw new \LogicException('Choice question must have at least 1 choice available.');
            }
            parent::__construct($question, $default);
            $this->setValidator($this->getDefaultValidator());
            $this->setAutocompleterValues($choices);
        }
        /**
         * @return array<string|bool|int|float|\Stringable>
         */
        public function getChoices(): array
        {
            return $this->choices;
        }
        /**
         * Sets multiselect option.
         *
         * When multiselect is set to true, multiple choices can be answered.
         *
         * @return $this
         */
        public function setMultiselect(bool $multiselect): static
        {
            $this->multiselect = $multiselect;
            $this->setValidator($this->getDefaultValidator());
            return $this;
        }
        /**
         * Returns whether the choices are multiselect.
         */
        public function isMultiselect(): bool
        {
            return $this->multiselect;
        }
        /**
         * Gets the prompt for choices.
         */
        public function getPrompt(): string
        {
            return $this->prompt;
        }
        /**
         * Sets the prompt for choices.
         *
         * @return $this
         */
        public function setPrompt(string $prompt): static
        {
            $this->prompt = $prompt;
            return $this;
        }
        /**
         * Sets the error message for invalid values.
         *
         * The error message has a string placeholder (%s) for the invalid value.
         *
         * @return $this
         */
        public function setErrorMessage(string $errorMessage): static
        {
            $this->errorMessage = $errorMessage;
            $this->setValidator($this->getDefaultValidator());
            return $this;
        }
        private function getDefaultValidator(): callable
        {
            $choices = $this->choices;
            $errorMessage = $this->errorMessage;
            $multiselect = $this->multiselect;
            $isAssoc = $this->isAssoc($choices);
            return function ($selected) use ($choices, $errorMessage, $multiselect, $isAssoc) {
                if ($multiselect) {
                    // Check for a separated comma values
                    if (!preg_match('/^[^,]+(?:,[^,]+)*$/', (string) $selected, $matches)) {
                        throw new InvalidArgumentException(\sprintf($errorMessage, $selected));
                    }
                    $selectedChoices = explode(',', (string) $selected);
                } else {
                    $selectedChoices = [$selected];
                }
                if ($this->isTrimmable()) {
                    foreach ($selectedChoices as $k => $v) {
                        $selectedChoices[$k] = trim((string) $v);
                    }
                }
                $multiselectChoices = [];
                foreach ($selectedChoices as $value) {
                    $results = [];
                    foreach ($choices as $key => $choice) {
                        if ($choice === $value) {
                            $results[] = $key;
                        }
                    }
                    if (\count($results) > 1) {
                        throw new InvalidArgumentException(\sprintf('The provided answer is ambiguous. Value should be one of "%s".', implode('" or "', $results)));
                    }
                    $result = array_search($value, $choices);
                    if (!$isAssoc) {
                        if (false !== $result) {
                            $result = $choices[$result];
                        } elseif (isset($choices[$value])) {
                            $result = $choices[$value];
                        }
                    } elseif (false === $result && isset($choices[$value])) {
                        $result = $value;
                    }
                    if (false === $result) {
                        throw new InvalidArgumentException(\sprintf($errorMessage, $value));
                    }
                    // For associative choices, consistently return the key as string:
                    $multiselectChoices[] = $isAssoc ? (string) $result : $result;
                }
                if ($multiselect) {
                    return $multiselectChoices;
                }
                return current($multiselectChoices);
            };
        }
    }
}

// file: vendor/symfony/console/Question/ConfirmationQuestion.php
namespace Symfony\Component\Console\Question {
    /**
     * Represents a yes/no question.
     *
     * @author Fabien Potencier <fabien@symfony.com>
     */
    class ConfirmationQuestion extends Question
    {
        /**
         * @param string $question        The question to ask to the user
         * @param bool   $default         The default answer to return, true or false
         * @param string $trueAnswerRegex A regex to match the "yes" answer
         */
        public function __construct(string $question, bool $default = true, private string $trueAnswerRegex = '/^y/i')
        {
            parent::__construct($question, $default);
            $this->setNormalizer($this->getDefaultNormalizer());
        }
        /**
         * Returns the default answer normalizer.
         */
        private function getDefaultNormalizer(): callable
        {
            $default = $this->getDefault();
            $regex = $this->trueAnswerRegex;
            return static function ($answer) use ($default, $regex) {
                if (\is_bool($answer)) {
                    return $answer;
                }
                $answerIsTrue = (bool) preg_match($regex, $answer);
                if (false === $default) {
                    return $answer && $answerIsTrue;
                }
                return '' === $answer || $answerIsTrue;
            };
        }
    }
}

