        public function codePointsAt(int $offset): array
        {
            $str = $this->slice($offset, 1);
            if ('' === $str->string) {
                return [];
            }
            $codePoints = [];
            foreach (preg_split('//u', $str->string, -1, \PREG_SPLIT_NO_EMPTY) as $c) {
                $codePoints[] = mb_ord($c, 'UTF-8');
            }
            return $codePoints;
        }
        public function folded(bool $compat = true): static
